import{_ as t,c as o,o as n,ai as i}from"./chunks/framework.C8-0bFZC.js";const u=JSON.parse('{"title":"Election Policy","description":"","frontmatter":{"layout":"ElectionPolicyThemeComponent","title":"Election Policy","sidebar":false,"aside":false,"hero":{"name":"Election Policy","subtitle":"The policy governing our committee elections."},"tilesHeading":"More Policies!","tiles":[{"title":"NeoNephos Charter","details":"Learn about our committees from our charter.","linkText":"Our Charter","linkUrl":"https://cdn.platform.linuxfoundation.org/agreements/neonephos-foundation.pdf?__hstc=81619592.11739e1f4ca03192f4e918409f725053.1748961872693.1755169332458.1755604645613.29&__hssc=81619592.2.1755604645613&__hsfp=1879682750"}]},"headers":[],"relativePath":"election_policy.md","filePath":"election_policy.md"}'),r={name:"election_policy.md"};function a(l,e,s,d,c,h){return n(),o("div",null,e[0]||(e[0]=[i('<h1 id="election-process-and-policy-for-neonephos-foundation" tabindex="-1">Election Process and Policy for NeoNephos Foundation <a class="header-anchor" href="#election-process-and-policy-for-neonephos-foundation" aria-label="Permalink to &quot;Election Process and Policy for NeoNephos Foundation&quot;">​</a></h1><p>NeoNephos Foundation seeks to hold open, fair, transparent, and efficient elections for various roles within the NeoNephos Foundation. See the chart before for the elections and role timelines for NeoNephos Foundation.</p><table tabindex="0"><thead><tr><th>Role</th><th>Period</th><th>Electorate Group</th><th>Number of Elected Individuals</th></tr></thead><tbody><tr><td>General Member Governing Board representative(s)</td><td>October 1 - September 30</td><td>NeoNephos General Sponsorship class</td><td>One for every five General Sponsors, minimum one representative and a maximum of three representatives ( see <a href="https://charter.neonephos.org" target="_blank" rel="noreferrer">NeoNephos Foundation Charter</a> section 2(c) ). If the number of General Sponsors changes, resulting in a change in the number of representatives, the current representative will serve until the end of their term, and the number of elected representatives will be adjusted for the next election.</td></tr><tr><td>Governing Board Chairperson</td><td>Reviewed annually by the Governing Board in October</td><td>Governing Board representatives</td><td>One.</td></tr><tr><td>Governing Board Treasurer</td><td>Reviewed annually by the Governing Board in October</td><td>Governing Board representatives</td><td>One.</td></tr><tr><td>TAC Vice Chairperson</td><td>Reviewed annually by the TAC in October</td><td>Voting TAC representatives</td><td>One.</td></tr><tr><td>TAC Vice Chairperson</td><td>Reviewed annually by the TAC in October</td><td>Voting TAC representatives</td><td>One.</td></tr></tbody></table><p>Elections are typically held in the month before the end date of each of the roles above. The exact timeline will be communicated to the electorate group, but it generally has the following structure:</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Election Notice</td><td>2 weeks</td></tr><tr><td>Nomination Period</td><td>1 week; closes at 11:59 pm Central European Time on the last day.</td></tr><tr><td>Review of Nominees</td><td>1 day</td></tr><tr><td>Election Period</td><td>1 week; closes at 11:59 pm Central European Time on the last day.</td></tr><tr><td>Announcement of Election Results</td><td>Day after Election Ends</td></tr></tbody></table><h2 id="eligibility" tabindex="-1">Eligibility <a class="header-anchor" href="#eligibility" aria-label="Permalink to &quot;Eligibility&quot;">​</a></h2><p>To serve on any governing body, council, or committee of the NeoNephos Foundation, an individual must:</p><ul><li>Be willing and able to fulfill the applicable responsibilities, and</li><li>Comply with all applicable policies of the Linux Foundation Europe and the NeoNephos Foundation, including the Linux Foundation Europe <a href="https://linuxfoundation.eu/policies/antitrust-policy" target="_blank" rel="noreferrer">Antitrust Policy</a> and <a href="https://linuxfoundation.eu/policies/code-of-conduct" target="_blank" rel="noreferrer">Code of Conduct</a>.</li></ul><p>Failure to meet these requirements may result in removal, suspension, or ineligibility to participate.</p><h2 id="nominations" tabindex="-1">Nominations <a class="header-anchor" href="#nominations" aria-label="Permalink to &quot;Nominations&quot;">​</a></h2><p>Nominations are done via email. Members of the electorate group may nominate someone else in the electorate group or self-nominate. All nominations must include the nominee’s name, company affiliation, and a short background on the nominee and why they wish to serve in the role. All nominations are confirmed before the election.</p><h2 id="elections" tabindex="-1">Elections <a class="header-anchor" href="#elections" aria-label="Permalink to &quot;Elections&quot;">​</a></h2><p>The election process uses <a href="https://docs.linuxfoundation.org/lfx/project-control-center/v2-latest-version/collaborations/voting#voting-for-a-poll" target="_blank" rel="noreferrer">LFX Voting</a>. Electors will check-box the individual(s) they wish to elect.</p><p>Election results will be announced to the electorate and the relevant committee the day after the election closes.</p><p>If you have any questions about the election process, please contact the NeoNephos Foundation staff at <a href="mailto:support@neonephos.org" target="_blank" rel="noreferrer">support@neonephos.org</a>.</p>',15)]))}const f=t(r,[["render",a]]);export{u as __pageData,f as default};
